use core::sync::atomic::{AtomicUsize, Ordering};
use std::sync::LazyLock;

struct SharedCounter {
    value: AtomicUsize,
}

impl SharedCounter {
    fn new() -> Self {
        SharedCounter { value: AtomicUsize::new(0) }
    }

    fn increment(&self) -> usize {
        self.value.fetch_add(1, Ordering::SeqCst) + 1
    }
}

struct Worker {
    id: usize,
    counter: &'static SharedCounter,
}

impl Worker {
    fn new(id: usize, counter: &'static SharedCounter) -> Self {
        Worker { id, counter }
    }

    fn run(&self) -> usize {
        let result = self.counter.increment();
        println!("Worker {} finished with value {}", self.id, result);
        result
    }
}

fn main() {
    static COUNTER: LazyLock<SharedCounter> = LazyLock::new(|| SharedCounter::new());

    let workers = vec![ 
        Worker::new(1, &*COUNTER), 
        Worker::new(2, &*COUNTER), 
        Worker::new(3, &*COUNTER) 
    ];

    let mut handles = Vec::new();
    for worker in workers {
        handles.push(worker);
    }

    let final_sum: usize = handles.into_iter().map(|w| w.run()).sum();
    println!("Final total count incremented: {}", final_sum);
}
